SELECT COUNT(search_id) AS num_searches
FROM flight_searches
WHERE user_id = 0;

SELECT DISTINCT u.user_name
FROM users u
JOIN user_bookings ub ON u.user_id = ub.user_id;

SELECT COUNT(*) AS confirmed_bookings
FROM user_bookings
WHERE user_id = 1 AND status = 'confirmed';

SELECT AVG(rating) AS average_rating
FROM flight_reviews
WHERE flight_id = 1;

SELECT MAX(price) AS max_price
  FROM price_trends
  WHERE airline_id = 1;

SELECT number_of_aircraft
FROM airline_fleet
WHERE airline_id = 0;

SELECT COUNT(*) AS total_paypal_payments
FROM user_payments
WHERE payment_method = 'PayPal';
